import "math"

// solve returns the minimum possible total sum of positive integers x used to make nums non-decreasing.
func solve(nums []int64) int64 {
	n := len(nums)
	if n <= 1 {
		return 0
	}

	// D[i] stores the minimum required total increase Delta[i] for nums[i].
	// We initialize D[0] = 0, as the minimum required increase at index 0 is 0.
	D := make([]int64, n)
	D[0] = 0

	// Step 1: Calculate the minimal required increases D[i]
	// D[i+1] must satisfy D[i+1] - D[i] >= nums[i] - nums[i+1] (R_i)
	// and D[i+1] >= 0.
	for i := 0; i < n-1; i++ {
		// R_i = nums[i] - nums[i+1]
		Ri := nums[i] - nums[i+1]

		// Minimum required value for D[i+1] based on D[i] and R_i
		requiredD := D[i] + Ri

		// D[i+1] must be non-negative
		if requiredD < 0 {
			D[i+1] = 0
		} else {
			D[i+1] = requiredD
		}
	}

	// Step 2: Calculate the minimum total sum S.
	// S is the sum of all positive jumps in D: S = sum(max(0, D[i] - D[i-1])).
	var S int64 = 0

	// i=0 case: D[-1] = 0
	S += max(0, D[0]) 

	for i := 1; i < n; i++ {
		diff := D[i] - D[i-1]
		S += max(0, diff)
	}

	return S
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}
