func solve(nums []int64) int64 {
	n := len(nums)
	if n <= 1 {
		return 0
	}

	var totalSum int64 = 0

	// A_prev corresponds to A_{i-1}. Start with A_{-1} = 0.
	var aPrev int64 = 0

	// M_current tracks max(nums[0]...nums[i]). Initialize with nums[0].
	var mCurrent int64 = nums[0]

	// A_0 is always 0.
	var aCurrent int64 = 0

	// Since A_0 = 0, the contribution for i=0 is max(0, 0 - 0) = 0.
	aPrev = aCurrent

	for i := 1; i < n; i++ {
		// 1. Update M_i = max(nums[0]...nums[i])
		if nums[i] > mCurrent {
			mCurrent = nums[i]
		}

		// 2. Calculate A_i = max(0, M_i - nums[0]) + nums[0] - nums[i]

		// Term 1: max(0, M_i - nums[0])
		term1 := int64(0)
		if mCurrent > nums[0] {
			term1 = mCurrent - nums[0]
		}

		// Term 2: nums[0] - nums[i]
		term2 := nums[0] - nums[i]

		aCurrent = term1 + term2

		// 3. Calculate contribution: max(0, A_i - A_{i-1})
		contribution := int64(0)
		if aCurrent > aPrev {
			contribution = aCurrent - aPrev
		}

		totalSum += contribution

		// Update previous A value for the next iteration
		aPrev = aCurrent
	}

	return totalSum
}

